const _mp = new Map<string, [number,number,number]>(
  NBA_MATCHUP_PROBS.map(([t1,t2,h,a,n]) => [`${t1}-${t2}`, [h, a, n]])
);

/** P(teamA wins) given location: 'home'=A is home, 'away'=B is home, 'neutral' */
export function getMatchupProb(teamAId: number, teamBId: number, loc: 'home'|'away'|'neutral'): number {
  const [lo, hi] = teamAId < teamBId ? [teamAId, teamBId] : [teamBId, teamAId];
  const row = _mp.get(`${lo}-${hi}`);
  if (!row) return 0.5;
  const [pLoHome, pHiHome, pNeu] = row;
  if (loc === 'neutral') return teamAId < teamBId ? pNeu : 1 - pNeu;
  if (loc === 'home')    return teamAId < teamBId ? pLoHome : 1 - pHiHome;
  /* away: teamA is away, teamB is home */
  return teamAId < teamBId ? pHiHome : 1 - pLoHome;
}
